 1	import { type FC, useMemo } from 'react';
 2	import InventoryNotReachable from 'src/modules/Providers/views/list/components/InventoryNotReachable';
 3	import ProviderCriticalCondition from 'src/modules/Providers/views/list/components/ProviderCriticalCondition';
 4	
 5	import type { V1beta1Provider } from '@kubev2v/types';
 6	import { PageSection } from '@patternfly/react-core';
 7	
 8	import './ProviderPageHeaderAlerts.style.scss';
 9	
10	type ProviderPageHeaderAlertsProps = {
11	  provider: V1beta1Provider;
12	  inventoryLoading: boolean;
13	  inventoryError: Error | null;
14	};
15	
16	const ProviderPageHeaderAlerts: FC<ProviderPageHeaderAlertsProps> = ({
17	  inventoryError,
18	  inventoryLoading,
19	  provider,
20	}) => {
21	  const criticalCondition = useMemo(
22	    () => provider?.status?.conditions?.find((condition) => condition?.category === 'Critical'),
23	    [provider?.status?.conditions],
24	  );
25	
26	  const isInventoryNotReachable = useMemo(
27	    () =>
28	      provider?.status?.phase === 'Ready' &&
29	      !inventoryLoading &&
30	      inventoryError &&
31	      inventoryError.toString() !== 'Error: Invalid provider data',
32	    [inventoryError, inventoryLoading, provider?.status?.phase],
33	  );
34	
35	  return (
36	    <>
37	      {isInventoryNotReachable && (
38	        <PageSection variant="light" className="forklift-page-header-alerts">
39	          <InventoryNotReachable key={'inventoryNotReachable'} />
40	        </PageSection>
41	      )}
42	      {criticalCondition && (
43	        <PageSection variant="light" className="forklift-page-header-alerts">
44	          <ProviderCriticalCondition
45	            type={criticalCondition?.type}
46	            message={criticalCondition?.message ?? ''}
47	            key={'providerCriticalCondition'}
48	          />
49	        </PageSection>
50	      )}
51	    </>
52	  );
53	};
54	
55	export default ProviderPageHeaderAlerts;

